{
  "learning_outcomes": [
    {
      "unit_name": "Unit 1: Solutions",
      "chapter_name": "Solutions",
      "topic": "Properties and concentration expressions",
      "outcomes": [
        "Calculate concentrations using various units."
      ]
    },
    {
      "unit_name": "Qualitative Analysis",
      "chapter_name": "Qualitative Analysis",
      "topic": "Identification techniques for ions in salts.",
      "outcomes": [
        "Identify one anion and one cation from a given salt sample using standard tests."
      ]
    },
    {
      "unit_name": "Unit 2: Electrochemistry",
      "chapter_name": "Electrochemistry",
      "topic": "Principles of electrochemical cells and energy conversion.",
      "outcomes": [
        "Differentiate between galvanic and electrolytic cells.",
        "Apply the Nernst equation to calculate cell potentials under non-standard conditions.",
        "Analyze conductance properties in electrolytic solutions.",
        "Explain mechanisms of batteries, fuel cells, and corrosion processes."
      ]
    },
    {
      "unit_name": "Unit 3: Chemical Kinetics",
      "chapter_name": "Chemical Kinetics",
      "topic": "Study of reaction rates and influencing factors.",
      "outcomes": [
        "Define rate of a chemical reaction and determine it experimentally.",
        "Analyze factors influencing the rate of reactions including concentration, temperature, and catalysts.",
        "Derive and apply integrated rate equations for zero and first-order reactions.",
        "Explain collision theory in the context of molecular interactions."
      ]
    },
    {
      "unit_name": "Unit 4: d and f Block Elements",
      "chapter_name": "d and f Block Elements",
      "topic": "Properties and applications of transition and inner-transition elements.",
      "outcomes": [
        "Correlate electronic configuration with position in the periodic table for d-block elements.",
        "Describe general properties including oxidation states, magnetic behavior, and catalytic activity.",
        "Explain characteristics of lanthanoids and actinoids.",
        "Identify applications of transition metals in industrial processes."
      ]
    },
    {
      "unit_name": "Unit 5: Coordination Compounds",
      "chapter_name": "Coordination Compounds",
      "topic": "Structure, bonding, and isomerism in coordination chemistry.",
      "outcomes": [
        "Apply Werner's theory to explain the structure of coordination compounds.",
        "Use IUPAC nomenclature rules for naming complex ions.",
        "Identify different types of isomerism (structural and stereoisomerism) in complexes.",
        "Compare bonding theories including Valence Bond Theory, Crystal Field Theory, and Metal Carbonyl bonding."
      ]
    },
    {
      "unit_name": "Unit 6: Haloalkanes and Haloarenes",
      "chapter_name": "Haloalkanes and Haloarenes",
      "topic": "Properties, preparation, and reactions of halogenated hydrocarbons.",
      "outcomes": [
        "Distinguish between haloalkanes and haloarenes based on structure and bonding.",
        "Apply IUPAC nomenclature rules for polyhalogen compounds.",
        "Predict products of substitution and elimination reactions in haloalkanes.",
        "Analyze the nature of C-X bonds and their reactivity."
      ]
    },
    {
      "unit_name": "Unit 7: Alcohols, Phenols and Ethers",
      "chapter_name": "Alcohols, Phenols and Ethers",
      "topic": "Classification and properties of oxygen-containing organic compounds.",
      "outcomes": [
        "Differentiate between alcohols, phenols, and ethers based on functional groups.",
        "Apply nomenclature rules for commercially important alcohols.",
        "Analyze physical properties including boiling points and solubility trends."
      ]
    },
    {
      "unit_name": "Unit 8: Aldehydes, Ketones and Carboxylic Acids",
      "chapter_name": "Aldehydes, Ketones and Carboxylic Acids",
      "topic": "Reactivity and synthesis of carbonyl compounds.",
      "outcomes": [
        "Identify functional groups in aldehydes, ketones, and carboxylic acids.",
        "Predict preparation methods for these compounds from precursors.",
        "Analyze physical properties and chemical reactions including nucleophilic addition."
      ]
    },
    {
      "unit_name": "Unit 9: Amines",
      "chapter_name": "Amines",
      "topic": "Structure, properties, and synthesis of nitrogen-containing compounds.",
      "outcomes": [
        "Distinguish primary, secondary, and tertiary amines based on structure.",
        "Apply nomenclature rules for substituted amines.",
        "Predict preparation methods including reduction of nitro compounds and Hofmann bromamide reaction."
      ]
    },
    {
      "unit_name": "Unit 10: Biomolecules",
      "chapter_name": "Biomolecules",
      "topic": "Chemistry of carbohydrates, proteins, and nucleic acids.",
      "outcomes": [
        "Classify biomolecules into carbohydrates, proteins, vitamins, hormones, and enzymes."
      ]
    },
    {
      "unit_name": "Surface Chemistry",
      "chapter_name": "Surface Chemistry",
      "topic": "Phenomena at interfaces and colloidal systems.",
      "outcomes": [
        "Differentiate between physisorption and chemisorption mechanisms."
      ]
    },
    {
      "unit_name": "General Principles and Processes of Isolation",
      "chapter_name": "General Principles and Processes of Isolation",
      "topic": "Methods for extraction and purification of elements.",
      "outcomes": [
        "Explain principles of concentration, oxidation, reduction, electrolytic refining."
      ]
    }
  ]
}
